// Function to set 'remember me' cookie
function setRememberMeCookie(username, passwordHash) {
  const expires = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000);
  document.cookie = `username=${encodeURIComponent(username)};expires=${expires.toUTCString()};path=/`;
  document.cookie = `passwordhash=${passwordHash};expires=${expires.toUTCString()};path=/`;
}

// Function to get 'remember me' cookie data
function getRememberMeCookieData() {
  const username = document.cookie.match(/username=([^;]*)/)[1];
  const passwordHash = document.cookie.match(/passwordhash=([^;]*)/)[1];
  if (username && passwordHash) return { username, passwordHash };
}

// Function to auto-login on subsequent visits
function autoLogin() {
  const rememberMeCookieData = getRememberMeCookieData();
  if (!rememberMeCookieData) return;
  login(rememberMeCookieData.username, rememberMeCookieData.passwordHash);
}

